#include<bits/stdc++.h>
using namespace std;
int a[110],dp[110][110];
bool check(int l,int r,int d)
{
    int len=r-l+1;
    if(len%d!=0)
    {
        return false;
    }
    for(int i=l;i+d<=r;i++)
    {
        if(a[i]!=a[i+d])
        {
            return false;
        }
    }
    return true;
}
int dfs(int l,int r)
{
    if(dp[l][r]!=-1)
    {
        return dp[l][r];
    }
    if(l==r)
    {
        return dp[l][r]=1;
    }
    int len=r-l+1;
    dp[l][r]=1e9;
    for(int i=1;i*i<=len;i++)
    {
        if(check(l,r,i))
        {
            dp[l][r]=min(dp[l][r],dfs(l,l+i-1));
        }
        if(len%i==0)
        {
            i=len/i;
            if(check(l,r,i))
            {
                dp[l][r]=min(dp[l][r],dfs(l,l+i-1));
            }
            i=len/i;
        }
    }
    for(int k=l;k<r;k++)
    {
        dp[l][r]=min(dp[l][r],dfs(l,k)+dfs(k+1,r));
    }
    return dp[l][r];
}
int main()
{
    int t;
    scanf("%d",&t);
    while(t--)
    {
        memset(dp,-1,sizeof(dp));
        int n,k;
        scanf("%d%d",&n,&k);
        for(int i=1;i<=n;i++)
        {
            scanf("%d",&a[i]);
        }
        if(dfs(1,n)<=k)
        {
            printf("YES\n");
        }
        else
        {
            printf("NO\n");
        }
    }
    return 0;
}
